// src/pages/Order.jsx
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import '../styles/style.css';

export default function Order() {
  const [menuData, setMenuData] = useState([]);
  const [fullName, setFullName] = useState('');
  const [phoneNumber, setPhoneNumber] = useState('');
  const [notes, setNotes] = useState('');
  const [quantities, setQuantities] = useState({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const navigate = useNavigate();

  useEffect(() => {
    const fetchMenu = async () => {
      try {
        const url = process.env.REACT_APP_API_URL
          ? `${process.env.REACT_APP_API_URL}/api/items`
          : 'http://localhost:5000/api/items';
        const res = await axios.get(url);

        const grouped = res.data.reduce((acc, item) => {
          const catName = item.category || 'Uncategorized';
          if (!acc[catName]) acc[catName] = [];
          acc[catName].push(item);
          return acc;
        }, {});

        const menuArr = Object.keys(grouped).map((cat, idx) => ({
          category: { category_id: idx, category_name: cat },
          items: grouped[cat],
        }));

        setMenuData(menuArr);
        setLoading(false);
      } catch (err) {
        console.error('Failed to load menu:', err);
        setError('Failed to load menu items');
        setLoading(false);
      }
    };
    fetchMenu();
  }, []);

  const handleQtyChange = (itemId, value) => {
    setQuantities(prev => ({ ...prev, [itemId]: parseInt(value) || 0 }));
  };

  const submitOrder = async (e) => {
    e.preventDefault();
    const itemsToSend = [];
    menuData.forEach(section =>
      section.items.forEach(it => {
        const qty = parseInt(quantities[it.item_id]) || 0;
        if (qty > 0) {
          itemsToSend.push({
            item_id: it.item_id,
            item_name: it.item_name || it.name,
            qty,
            price: parseFloat(it.price)
          });
        }
      })
    );

    if (!itemsToSend.length) return alert('Please select at least one item');

    const payload = { fullName, phoneNumber, notes, items: itemsToSend, date: new Date().toISOString(), orderId: Date.now() };

    try {
      const existingOrders = JSON.parse(localStorage.getItem('orders')) || [];
      localStorage.setItem('orders', JSON.stringify([...existingOrders, payload]));

      const url = process.env.REACT_APP_API_URL
        ? `${process.env.REACT_APP_API_URL}/api/orders`
        : 'http://localhost:5000/api/orders';
      await axios.post(url, payload);

      navigate('/order-confirmation', { state: payload });
      setFullName(''); setPhoneNumber(''); setNotes(''); setQuantities({});
    } catch (err) {
      console.error('Failed to submit order:', err.response || err);
      alert(err.response?.data?.message || 'Failed to submit order');
    }
  };

  return (
    <section className="order-page" style={{
      display: 'flex',
      justifyContent: 'center',
      padding: '50px 20px',
      background: '#f8f8f8'
    }}>
      <div className="order-card" style={{
        background: '#fff',
        padding: '30px 40px',
        borderRadius: '16px',
        boxShadow: '0 10px 25px rgba(0,0,0,0.1)',
        maxWidth: '700px',
        width: '100%'
      }}>
        <button 
          className="back-home-btn" 
          onClick={() => navigate('/home')}
          style={{
            background: '#d35400',
            color: '#fff',
            border: 'none',
            borderRadius: '8px',
            padding: '8px 16px',
            cursor: 'pointer',
            marginBottom: '20px'
          }}
        >
          ← Back to Home
        </button>

        <h2 style={{ color: '#d35400', marginBottom: '10px' }}>Place Your Order</h2>
        <p style={{ color: '#555', marginBottom: '30px' }}>Select your favorite items and confirm your order</p>

        {loading && <p style={{ color: '#555' }}>⏳ Loading menu items...</p>}
        {error && <p style={{ color: 'red' }}>{error}</p>}

        {!loading && !error && (
          <form onSubmit={submitOrder} style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
            <input 
              type="text" 
              value={fullName} 
              onChange={e => setFullName(e.target.value)} 
              placeholder="Full Name" 
              required
              style={{ padding: '10px', borderRadius: '8px', border: '1px solid #ccc', width: '100%' }}
            />
            <input 
              type="tel" 
              value={phoneNumber} 
              onChange={e => setPhoneNumber(e.target.value)} 
              placeholder="Phone Number" 
              required
              style={{ padding: '10px', borderRadius: '8px', border: '1px solid #ccc', width: '100%' }}
            />

            {menuData.map(section => (
              <fieldset key={section.category.category_id} style={{ border: '1px solid #eee', borderRadius: '12px', padding: '15px' }}>
                <legend style={{ color: '#d35400', fontWeight: 'bold' }}>{section.category.category_name}</legend>
                {section.items.map(item => (
                  <div key={item.item_id} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '10px' }}>
                    <input 
                      type="number" 
                      min="0" 
                      value={quantities[item.item_id] || 0} 
                      onChange={e => handleQtyChange(item.item_id, e.target.value)} 
                      style={{ width: '60px', padding: '5px', borderRadius: '8px', border: '1px solid #ccc' }}
                    />
                    <span style={{ flex: 1, marginLeft: '15px', color: '#555' }}>{item.item_name}</span>
                    <span style={{ color: '#d35400', fontWeight: 'bold' }}>${parseFloat(item.price).toFixed(2)}</span>
                  </div>
                ))}
              </fieldset>
            ))}

            <textarea 
              value={notes} 
              onChange={e => setNotes(e.target.value)} 
              rows="3" 
              placeholder="Additional Notes (optional)" 
              style={{ padding: '10px', borderRadius: '8px', border: '1px solid #ccc', width: '100%' }}
            />

            <button type="submit" style={{
              background: '#d35400',
              color: '#fff',
              border: 'none',
              borderRadius: '12px',
              padding: '12px',
              fontSize: '1rem',
              cursor: 'pointer'
            }}>
              Submit Order
            </button>
          </form>
        )}
      </div>
    </section>
  );
}
